INSERT INTO `majors` (`name_ar`, `name_en`, `description`, `required_skills`, `career_opportunities`, `difficulty_level`, `demand_level`, `salary_range`) VALUES
('علوم الحاسب', 'Computer Science', 'دراسة نظرية الحاسوب والبرمجة والخوارزميات والذكاء الاصطناعي', 'البرمجة, الرياضيات, حل المشكلات, التفكير المنطقي, الإبداع التقني', 'مبرمج, محلل بيانات, مهندس AI, مطور ويب, مهندس برمجيات, متخصص أمن معلومات', 'high', 'high', '12,000 - 30,000 ريال'),
('الطب البشري', 'Medicine', 'دراسة جسم الإنسان وتشخيص وعلاج الأمراض والوقاية منها', 'الصبر, الدقة, التعاطف, الذاكرة القوية, القدرة على التحليل, العمل تحت الضغط', 'طبيب عام, أخصائي, استشاري, باحث طبي, جراح, طبيب طوارئ', 'high', 'high', '20,000 - 50,000 ريال'),
('الهندسة الكهربائية', 'Electrical Engineering', 'دراسة الكهرباء والإلكترونيات والطاقة والاتصالات', 'الرياضيات, الفيزياء, التحليل, التصميم, حل المشكلات التقنية', 'مهندس كهرباء, مهندس طاقة, مهندس إلكترونيات, مهندس اتصالات, مهندس تحكم', 'high', 'high', '14,000 - 32,000 ريال'),
('إدارة الأعمال', 'Business Administration', 'دراسة مبادئ الإدارة والتخطيط الاستراتيجي وإدارة الموارد', 'القيادة, التنظيم, التواصل, التحليل المالي, اتخاذ القرار, التفاوض', 'مدير مشروع, مستشار إداري, محلل أعمال, مدير موارد بشرية, رائد أعمال', 'medium', 'high', '10,000 - 25,000 ريال'),
('التصميم الجرافيكي', 'Graphic Design', 'فن التواصل البصري والتصميم الإبداعي للمطبوعات والوسائط الرقمية', 'الإبداع, التذوق الفني, البرامج التقنية (Photoshop, Illustrator), التواصل البصري', 'مصمم جرافيك, مصمم واجهات UI/UX, مصمم هوية بصرية, مصمم إعلانات, فنان رقمي', 'low', 'medium', '6,000 - 15,000 ريال'),
('الهندسة المعمارية', 'Architecture', 'تصميم وتخطيط المباني والمساحات الحضرية', 'الإبداع, الرسم, الرياضيات, الهندسة, التخطيط المكاني, الابتكار', 'مهندس معماري, مخطط عمراني, مصمم داخلي, مستشار معماري, مدير مشاريع بناء', 'high', 'medium', '12,000 - 28,000 ريال'),
('علم النفس', 'Psychology', 'دراسة السلوك البشري والعمليات العقلية والاضطرابات النفسية', 'الاستماع, التعاطف, التحليل, البحث العلمي, الصبر, التواصل الفعال', 'أخصائي نفسي, مستشار نفسي, باحث, معالج سلوكي, أخصائي تنمية بشرية', 'medium', 'medium', '8,000 - 20,000 ريال'),
('الهندسة الميكانيكية', 'Mechanical Engineering', 'تصميم وتحليل الأنظمة الميكانيكية والحرارية', 'الرياضيات, الفيزياء, التصميم, حل المشكلات, الإبداع التقني, التفكير التحليلي', 'مهندس ميكانيكي, مهندس تصنيع, مهندس صيانة, مهندس سيارات, مستشار هندسي', 'high', 'high', '13,000 - 30,000 ريال'),
('تقنية المعلومات', 'Information Technology', 'إدارة وتطبيق التقنيات الحاسوبية في بيئات الأعمال', 'معرفة بالحاسوب, القدرة على التعلم المستمر, مهارات التواصل, حل المشكلات التقنية', 'مدير أنظمة, أخصائي أمن سيبراني, مسؤول قواعد بيانات, محلل أنظمة, مدير شبكات', 'medium', 'high', '12,000 - 25,000 ريال'),
('المحاسبة', 'Accounting', 'تسجيل وتحليل المعاملات المالية وإعداد التقارير', 'الدقة, التنظيم, الرياضيات, التحليل المالي, الالتزام, الأمانة', 'محاسب, مدقق حسابات, محلل مالي, مستشار ضريبي, مدير مالي', 'medium', 'high', '8,000 - 20,000 ريال');
INSERT INTO `questions` (`question_text`, `question_type`, `category`, `options`, `weight`) VALUES
('ما هي المواد الدراسية التي تفضلها؟', 'subject', 'academic', '["الرياضيات", "الفيزياء", "الكيمياء", "الأحياء", "اللغة العربية", "اللغة الإنجليزية", "التاريخ", "الجغرافيا", "الحاسب الآلي", "الفن والتصميم"]', 1.20),
('ما هي المهارات التي تتمتع بها أكثر؟', 'skill', 'personal', '["التحليل المنطقي", "الإبداع والابتكار", "التواصل الفعال", "القيادة والتأثير", "العمل الجماعي", "حل المشكلات", "التنظيم والتخطيط", "الاستماع الجيد"]', 1.20),
('ماذا تفضل في وقت فراغك؟', 'interest', 'hobbies', '["القراءة والكتابة", "الرسم والتصميم", "البرمجة والتقنية", "الرياضة والنشاط", "التعلم والدورات", "مساعدة الآخرين", "الاكتشاف والبحث", "مشاهدة الأفلام"]', 1.10),
('في أي بيئة تفضل العمل؟', 'personality', 'work_environment', '["المكتب التقليدي", "العمل الميداني", "المختبرات والأبحاث", "العمل عن بعد", "ورش العمل", "البيئة الإبداعية", "المستشفى أو العيادة"]', 1.00),
('ما هي نقاط قوتك الرئيسية؟', 'strength', 'personal', '["التفكير التحليلي", "الإبداع والابتكار", "مهارات التواصل", "القدرة على التعلم السريع", "الصبر والتحمل", "القيادة والمسؤولية", "الدقة والانتباه للتفاصيل"]', 1.30),
('أي من هذه الأنشطة تستمتع بها؟', 'interest', 'activities', '["حل الألغاز والمسائل الرياضية", "التصميم والفن", "الكتابة والتأليف", "التجارب العملية", "التفاعل الاجتماعي", "الألعاب الاستراتيجية", "التطوع ومساعدة الآخرين"]', 1.00),
('كيف تفضل حل المشاكل؟', 'skill', 'problem_solving', '["التحليل المنطقي والأرقام", "الإبداع والحلول غير التقليدية", "البحث والقراءة المستفيضة", "التجربة العملية", "النقاش مع الآخرين", "التخطيط المنهجي"]', 1.20),
('ما مستوى اهتمامك بالتكنولوجيا؟', 'interest', 'technology', '["مهتم جداً ومتابع للجديد", "مهتم ومستخدم نشط", "استخدام عادي للضرورة", "اهتمام محدود", "غير مهتم بالتكنولوجيا"]', 1.10),
('ما هو أسلوب التعلم المفضل لديك؟', 'personality', 'learning_style', '["التعلم النظري والقراءة", "التطبيق العملي والتجريب", "الشرح المرئي والفيديو", "المناقشة والحوار", "التعلم الذاتي الموجه"]', 1.00),
('ما مدى استعدادك للتعامل مع الضغوطات؟', 'strength', 'stress_management', '["قادر على التعامل مع ضغوط عالية جداً", "أتعامل جيداً مع الضغوط المتوسطة", "أفضل بيئة عمل هادئة", "أفضل العمل بدون ضغوط تماماً"]', 1.00),
('ما مدى اهتمامك بمساعدة الآخرين؟', 'interest', 'social', '["مهم جداً بالنسبة لي - أولوية", "مهم ولكن ليس الأولوية الأولى", "اهتمام متوسط", "ليس من أولوياتي"]', 1.10),
('هل تفضل العمل الفردي أم الجماعي؟', 'personality', 'work_style', '["العمل الفردي تماماً", "أفضل الفردي مع تعاون محدود", "مزيج متوازن بين الاثنين", "أفضل الجماعي مع استقلالية", "العمل الجماعي تماماً"]', 1.00),
('ما مستوى قدرتك على التحدث أمام الجمهور؟', 'skill', 'public_speaking', '["ممتاز وأستمتع به كثيراً", "جيد وأستطيع القيام به", "مقبول مع بعض التوتر", "صعب جداً بالنسبة لي"]', 0.90),
('كم ساعة تستطيع قضاءها في القراءة والدراسة يومياً؟', 'personality', 'study_habits', '["أكثر من 4 ساعات بارتياح", "2-4 ساعات يومياً", "1-2 ساعة يومياً", "أقل من ساعة"]', 1.00),
('ما مدى اهتمامك بالتفاصيل الدقيقة؟', 'skill', 'attention_to_detail', '["أهتم كثيراً بأدق التفاصيل", "أهتم بالتفاصيل المهمة", "أركز على الصورة الكبرى", "التفاصيل ليست مهمة بالنسبة لي"]', 1.10),
('ما مدى تقبلك للمخاطرة والتجريب؟', 'personality', 'risk_tolerance', '["أحب المخاطرة والتجارب الجديدة", "مستعد للمخاطرة المحسوبة", "أفضل الأمان والاستقرار", "أتجنب المخاطرة تماماً"]', 0.90),
('هل تفضل الأعمال الروتينية أم المتغيرة؟', 'personality', 'routine_preference', '["أفضل التنوع والت غيير المستمر", "مزيج من الاثنين", "أفضل الروتين مع بعض التنوع", "أفضل الروتين التام"]', 0.80),
('ما مدى اهتمامك بالمال والرواتب؟', 'interest', 'financial', '["الأولوية الأولى", "مهم جداً", "مهم لكن ليس الأهم", "ليس مهماً كثيراً"]', 0.70),
('هل تفضل العمل في القطاع العام أم الخاص؟', 'personality', 'sector_preference', '["القطاع الخاص - الشركات", "القطاع الحكومي", "لا فرق بالنسبة لي", "العمل الحر والخاص بي"]', 0.60),
('كم سنة تستطيع الدراسة الجامعية؟', 'personality', 'study_duration', '["6-7 سنوات أو أكثر", "4-5 سنوات", "2-3 سنوات فقط", "أقصر مدة ممكنة"]', 0.80);
